  return (
    <div className="grid-container">
      {/* Pavé 1 */}
      <div className="pave">
        Construire un site web responsive et dynamique s’adaptant à tout type
        d’écran grâce à l’intégration des éléments des maquettes graphiques
        (développement front-end avec HTML, CSS, JavaScript et React)
      </div>
      {/* Pavé 2 */}
      <div className="pave">Pavé 2</div>
      {/* Pavé 3 */}
      <div className="pave">Pavé 3</div>
      {/* Pavé 4 */}
      <div className="pave">Pavé 4</div>
      {/* Pavé 5 */}
      <div className="pave">Pavé 5</div>
      {/* Pavé 6 */}
      <div className="pave">Pavé 6</div>
    </div>
  );
}

export default Grid;
